+        model.dispatch_action_menu_selection(
+            ActionKind::ConfirmThenExecute {
+                title: "Release?".to_string(),
+                message: "Confirm release".to_string(),
+                operation: "release:7".to_string(),
+            },
+            "reservation:7",
+        );
